import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String userInput = request.getParameter("input");

        // Sanitize and escape user input before outputting it to the response
        userInput = sanitizeUserInput(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + userInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeUserInput(String input) {
        // Replace characters that are significant in HTML with their HTML entity equivalents
        input = input.replace("&", "&amp;")
                     .replace("<", "&lt;")
                     .replace(">", "&gt;")
                     .replace("\"", "&quot;")
                     .replace("'", "&#39;");

        return input;
    }
}
``

